class Solution:
    def removeSubstring(self, s, k):
        stack = []  # list of [char, count]
        for c in s:
            if stack and stack[-1][0] == c:
                stack[-1][1] += 1
            else:
                stack.append([c, 1])
            if (c == ')' and stack[-1][1] >= k and len(stack) >= 2
                    and stack[-2][0] == '(' and stack[-2][1] >= k):
                # remove exactly k closes and k opens
                stack[-1][1] -= k
                stack[-2][1] -= k
                if stack[-1][1] == 0:
                    stack.pop()
                if stack and stack[-1][1] == 0:
                    stack.pop()
                # merge newly adjacent equal runs
                if len(stack) >= 2 and stack[-1][0] == stack[-2][0]:
                    stack[-2][1] += stack[-1][1]
                    stack.pop()
        return ''.join(ch * cnt for ch, cnt in stack)

