var removeSubstring = function(s, k) {
    const stack = [];
    for (const c of s) {
        if (stack.length && stack[stack.length - 1][0] === c) {
            stack[stack.length - 1][1] += 1;
        } else {
            stack.push([c, 1]);
        }
        const top = stack[stack.length - 1];
        if (c === ')' && top[1] >= k && stack.length >= 2 &&
            stack[stack.length - 2][0] === '(' && stack[stack.length - 2][1] >= k) {
            stack[stack.length - 1][1] -= k;
            stack[stack.length - 2][1] -= k;
            if (stack[stack.length - 1][1] === 0) stack.pop();
            if (stack.length && stack[stack.length - 1][1] === 0) stack.pop();
            if (stack.length >= 2 && stack[stack.length - 1][0] === stack[stack.length - 2][0]) {
                stack[stack.length - 2][1] += stack[stack.length - 1][1];
                stack.pop();
            }
        }
    }
    let res = '';
    for (const [ch, cnt] of stack) res += ch.repeat(cnt);
    return res;
};
